const d = $input.first().json;

if (!/^[a-z0-9-]+$/.test(d.slug)) throw new Error('Slug must be lowercase letters, numbers, hyphens only');

function genHex(len) {
  let s = '';
  for (let i = 0; i < len; i++) s += Math.floor(Math.random() * 16).toString(16);
  return s;
}

const webhook_secret = genHex(48);
const jwt_secret = genHex(64);

let field_map = {};
try { field_map = JSON.parse(d.field_map || '{}'); } catch(e) {}

const config = {
  lead_capture: {
    field_map,
    notify_email: d.notify_email,
    from_name: d.from_name,
    from_email: d.from_email,
    business_description: d.business_description || '',
    notify_phone: d.notify_phone || '',
    lead_notify_method: d.lead_notify_method || 'email',
    sheet_id: ''
  },
  vertical: d.vertical
};

return [{ json: {
  slug: d.slug,
  name: d.name,
  webhook_secret,
  jwt_secret,
  config_json: JSON.stringify(config)
}}];
